target.css:
:root {
  --bg-notification: #ffffff;
  --text-title: #1a1a2e;
  --text-subtitle: #6b7280;
  --badge-bg: #ef4444;
  --badge-text: #ffffff;
  --border: #e5e7eb;
  --icon-bg: #f3f4f6;
}

.notification {
  display: flex;
  align-items: center;
  gap: 12px;
  background: var(--bg-notification);
  border: 2px solid var(--border);
  border-radius: 12px;
  padding: 16px;
  width: 300px;
}

.icon {
  width: 40px;
  height: 40px;
  background: var(--icon-bg);
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  flex-shrink: 0;
}

.content {
  flex: 1;
  min-width: 0;
}

.title {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-title);
}

.subtitle {
  font-size: 12px;
  color: var(--text-subtitle);
  margin-top: 2px;
}

.badge {
  width: 24px;
  height: 24px;
  background: var(--badge-bg);
  color: var(--badge-text);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  font-weight: 700;
  flex-shrink: 0;
}
